import{_ as e,o as i,c as o,ak as r}from"./chunks/framework.DkeEmzcj.js";const y=JSON.parse('{"title":"Privacy Policy - M.A.G.I.C.","description":"","frontmatter":{"title":"Privacy Policy - M.A.G.I.C."},"headers":[],"relativePath":"magic-games/privacy-policy.md","filePath":"magic-games/privacy-policy.md","lastUpdated":1772239018000}'),t={name:"magic-games/privacy-policy.md"};function n(s,a,c,l,d,h){return i(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to “Privacy Policy”">​</a></h1><p>This Privacy Policy describes how <strong>M.A.G.I.C. — Many Amazing Games In Collection</strong> (“the App”) handles your information when you use the App.</p><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h2><p>M.A.G.I.C. is a collection of casual mini-games designed for entertainment and relaxation. We are committed to protecting your privacy and keeping your experience simple, safe, and transparent.</p><h2 id="information-we-do-not-collect" tabindex="-1">Information We DO NOT Collect <a class="header-anchor" href="#information-we-do-not-collect" aria-label="Permalink to “Information We DO NOT Collect”">​</a></h2><p><strong>M.A.G.I.C. itself does NOT collect, store, transmit, or share any personal information.</strong></p><ul><li>No names, email addresses, phone numbers, or identifiers.</li><li>No device tracking, IP tracking, or location tracking.</li><li>No gameplay analytics or usage profiling by us.</li><li>No crash logs or diagnostics are sent to our servers.</li></ul><h2 id="advertising-third-party-services" tabindex="-1">Advertising &amp; Third-Party Services <a class="header-anchor" href="#advertising-third-party-services" aria-label="Permalink to “Advertising &amp; Third-Party Services”">​</a></h2><p>M.A.G.I.C. may display advertisements provided by third-party advertising networks (such as Google AdMob).</p><p>These ad providers may automatically collect certain non-personal information such as device identifiers, approximate location, or interaction data in order to show relevant ads and measure performance.</p><p>This data collection is governed by the privacy policies of the respective ad providers. We do not control, store, or have access to this information.</p><h2 id="how-your-data-is-handled" tabindex="-1">How Your Data Is Handled <a class="header-anchor" href="#how-your-data-is-handled" aria-label="Permalink to “How Your Data Is Handled”">​</a></h2><p>All game progress, scores, and settings are stored locally on your device.</p><p><strong>Local Processing:</strong> The App works primarily offline. No personal data is transmitted by us.</p><p><strong>No Cloud Storage:</strong> We do not maintain user accounts or cloud backups.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to “Permissions”">​</a></h2><p>The App may request minimal device permissions required for core functionality (such as saving game progress). No permission is used for data collection by us.</p><h2 id="children-s-privacy" tabindex="-1">Children’s Privacy <a class="header-anchor" href="#children-s-privacy" aria-label="Permalink to “Children’s Privacy”">​</a></h2><p>M.A.G.I.C. is not intended for children under 13. We do not knowingly collect personal information from children.</p><h2 id="changes-to-this-policy" tabindex="-1">Changes to This Policy <a class="header-anchor" href="#changes-to-this-policy" aria-label="Permalink to “Changes to This Policy”">​</a></h2><p>We may update our Privacy Policy from time to time. We will notify you of any changes by posting the new Privacy Policy on this page. You are advised to review this Privacy Policy periodically for any changes. Changes to this Privacy Policy are effective when they are posted on this page.</p><h2 id="contact-us" tabindex="-1">Contact Us <a class="header-anchor" href="#contact-us" aria-label="Permalink to “Contact Us”">​</a></h2><p>If you have any questions or suggestions about our Privacy Policy, please do not hesitate to contact us at:<br><a href="mailto:bxamra@icloud.com" target="_blank" rel="noreferrer">bxamra@icloud.com</a></p>',23)])])}const m=e(t,[["render",n]]);export{y as __pageData,m as default};
